import { createContext, useContext, useState, useEffect, useCallback } from 'react';

const AuthContext = createContext();
const API = import.meta.env.VITE_API_URL || 'http://localhost:5000/api';

export const ROLES = {
  MD_CEO:             'MD_CEO',
  CEO:                'CEO',
  COO:                'COO',
  BRANCH_HEAD:        'BRANCH_HEAD',
  ADMIN:              'ADMIN',
  SALES_EXEC:         'SALES_EXEC',
  SALES_MANAGER:      'SALES_MANAGER',
  FIELD_EXEC:         'FIELD_EXEC',
  HR:                 'HR',
  DESIGNER:           'DESIGNER',
  OPERATION_EXEC:     'OPERATION_EXEC',
  OPERATION_MANAGER:  'OPERATION_MANAGER',
  PRODUCTION_EXEC:    'PRODUCTION_EXEC',
  PRODUCTION_MANAGER: 'PRODUCTION_MANAGER',
  AGENT:              'AGENT',
  VENDOR:             'VENDOR',
  IT:                 'IT',
  ACCOUNTS:           'ACCOUNTS',
};

export const AuthProvider = ({ children }) => {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true); // checking localStorage on mount
  const [error, setError]     = useState(null);

  // ── Restore session from localStorage on mount ──────────────────
  useEffect(() => {
    const stored = localStorage.getItem('gms_user');
    if (stored) {
      try { setUser(JSON.parse(stored)); } catch {}
    }
    setLoading(false);
  }, []);

  // ── Login ────────────────────────────────────────────────────────
  const login = useCallback(async (loginId, password) => {
    setError(null);
    try {
      const res = await fetch(`${API}/auth/login`, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify({ login: loginId, password }),
      });
      let data = {};
      const text = await res.text();
      if (text) {
        try {
          data = JSON.parse(text);
        } catch (e) {
          data = { message: text };
        }
      }
      if (!res.ok) throw new Error(data.message || 'Login failed.');

      localStorage.setItem('gms_user', JSON.stringify(data));
      setUser(data);
      return { success: true, mustChangePassword: data.mustChangePassword };
    } catch (err) {
      setError(err.message);
      return { success: false, error: err.message };
    }
  }, []);

  // ── Logout ───────────────────────────────────────────────────────
  const logout = useCallback(() => {
    localStorage.removeItem('gms_user');
    setUser(null);
  }, []);

  // ── Change password (first-login or voluntary) ───────────────────
  const changePassword = useCallback(async (currentPassword, newPassword) => {
    setError(null);
    try {
      const res = await fetch(`${API}/auth/change-password`, {
        method:  'POST',
        headers: {
          'Content-Type':  'application/json',
          'Authorization': `Bearer ${user?.token}`,
        },
        body: JSON.stringify({ currentPassword, newPassword }),
      });
      let data = {};
      const text = await res.text();
      if (text) {
        try {
          data = JSON.parse(text);
        } catch (e) {
          data = { message: text };
        }
      }
      if (!res.ok) throw new Error(data.message || 'Failed to change password.');

      // Clear mustChangePassword flag locally
      const updated = { ...user, mustChangePassword: false };
      localStorage.setItem('gms_user', JSON.stringify(updated));
      setUser(updated);
      return { success: true };
    } catch (err) {
      return { success: false, error: err.message };
    }
  }, [user]);

  // ── Refresh profile from server ──────────────────────────────────
  const refreshProfile = useCallback(async () => {
    if (!user?.token) return;
    try {
      const res = await fetch(`${API}/auth/me`, {
        headers: { 'Authorization': `Bearer ${user.token}` },
      });
      if (res.ok) {
        let data = {};
        const text = await res.text();
        if (text) {
          try {
            data = JSON.parse(text);
          } catch (e) {
            data = { message: text };
          }
        }
        const updated = { ...user, ...data };
        localStorage.setItem('gms_user', JSON.stringify(updated));
        setUser(updated);
      }
    } catch {}
  }, [user]);

  // ── Convenience: authenticated fetch ────────────────────────────
  const authFetch = useCallback((url, options = {}) => {
    return fetch(`${API}${url}`, {
      ...options,
      headers: {
        'Content-Type':  'application/json',
        'Authorization': `Bearer ${user?.token}`,
        ...(options.headers || {}),
      },
    });
  }, [user]);

  return (
    <AuthContext.Provider value={{
      user, loading, error,
      login, logout, changePassword, refreshProfile, authFetch,
      ROLES,
      isAuthenticated: !!user,
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

/**
 * useApi — Central data-fetching hook.
 * Wraps fetch with auth token, loading/error state, and auto-retry.
 *
 * Usage:
 *   const { data, loading, error, refetch } = useApi('/employees');
 *   const { request } = useApi();
 *   await request('POST', '/employees', body);
 */
import { useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from '../context/AuthContext';

const BASE = import.meta.env.VITE_API_URL || '/api';

export const useApi = (path = null, options = {}) => {
  const { user } = useAuth();
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(!!path);
  const [error,   setError]   = useState(null);
  const abortRef = useRef(null);

  const token = user?.token;

  const fetchData = useCallback(async (overridePath) => {
    const url = overridePath || path;
    if (!url) return;

    // Cancel previous in-flight request
    if (abortRef.current) abortRef.current.abort();
    abortRef.current = new AbortController();

    setLoading(true);
    setError(null);

    try {
      const res = await fetch(`${BASE}${url}`, {
        signal: abortRef.current.signal,
        headers: {
          'Content-Type': 'application/json',
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        ...options,
      });
      let json = {};
      const text = await res.text();
      if (text) {
        try {
          json = JSON.parse(text);
        } catch (e) {
          json = { message: text };
        }
      }
      if (!res.ok) {
        if (res.status === 401) {
          localStorage.removeItem('gms_user');
          window.location.href = '/login';
          return;
        }
        setError(json.message || `HTTP ${res.status}`);
        return;
      }
      setData(json);
      return json;
    } catch (err) {
      if (err.name === 'AbortError') return;
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [path, token]); // eslint-disable-line

  useEffect(() => {
    if (path) fetchData();
    return () => abortRef.current?.abort();
  }, [path, token]); // eslint-disable-line

  // Generic request method for mutations (POST/PUT/PATCH/DELETE)
  const request = useCallback(async (method, url, body) => {
    const res = await fetch(`${BASE}${url}`, {
      method,
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {}),
      },
      body: body ? JSON.stringify(body) : undefined,
    });
    let json = {};
    const text = await res.text();
    if (text) {
      try {
        json = JSON.parse(text);
      } catch (e) {
        json = { message: text };
      }
    }
    if (!res.ok) throw new Error(json.message || `HTTP ${res.status}`);
    return json;
  }, [token]);

  return { data, loading, error, refetch: fetchData, request };
};

export default useApi;

