// ── Components ────────────────────────────────────────────────────────────────
const Badge = ({ value, label }) => {
  const styles = {
    EMPLOYEE_CREATE: 'bg-emerald-50 text-emerald-700 border-emerald-100',
    EMPLOYEE_UPDATE: 'bg-blue-50 text-blue-700 border-blue-100',
