      {activeTab === 'ASSIGN' && isManagerOrAdmin && (
        <form onSubmit={handleAssignTarget} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200 max-w-4xl mx-auto space-y-8">
          <div className="border-b pb-6">
