              value={phone} 
              onChange={e => {
                setError('');
                setPhone(e.target.value.replace(/\D/g, '').slice(0, 10));
              }} 
              placeholder="Enter mobile number" 
              className="h-10 w-full rounded border border-slate-300 bg-background px-3 text-sm outline-none focus:border-[#003366]" 
