import { useState } from 'react';
import { prospectApi, orderApi, paymentApi, brochureApi } from '../../../services/api';

export const useProspectFlow = (user, onSaved) => {
  const [showPhoneSearch, setShowPhoneSearch] = useState(false);
  const [showProspectDetails, setShowProspectDetails] = useState(null);
  const [showCreateProspect, setShowCreateProspect] = useState(null);
  const [showQuotation, setShowQuotation] = useState(null);
  const [showUpdateStatus, setShowUpdateStatus] = useState(null);
  const [showScheduleAppointment, setShowScheduleAppointment] = useState(null);
  const [showBrochureSelector, setShowBrochureSelector] = useState(null);
  const [toastMsg, setToastMsg] = useState(null);

  const handlePhoneSearch = async (searchParams) => {
    setShowPhoneSearch(false);
    try {
      const res = await prospectApi.searchPhone(searchParams, user?.token);
      if (res.found && res.data) {
        setShowProspectDetails(res.data);
      } else {
        setShowCreateProspect({ phone: searchParams.phone, company: searchParams.company });
      }
    } catch (err) {
      setToastMsg('Error searching prospect');
      setTimeout(() => setToastMsg(null), 3000);
    }
  };

  const handleProspectSubmit = async (formData) => {
    try {
      const payload = {
        name: formData.name,
        company: formData.company,
        phone: formData.phone,
        source: formData.source,
        priority: formData.priority,
        clientType: formData.clientType,
        requirement: { 
          service: formData.products ? formData.products.join(', ') : '', 
          notes: formData.notes, 
          location: formData.location, 
          budget: formData.budget 
        },
        nextFollowUpDate: formData.nextFollowUpDate || undefined,
      };

      if (showCreateProspect?._id || showCreateProspect?.id) {
        await prospectApi.update(showCreateProspect._id || showCreateProspect.id, payload, user?.token);
        setToastMsg('Prospect updated successfully!');
      } else {
        await prospectApi.create(payload, user?.token);
        setToastMsg('Prospect submitted successfully!');
      }
      setShowCreateProspect(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg(err.message || 'Failed to save prospect');
      setTimeout(() => setToastMsg(null), 5000);
    }
  };

  const handleUpdateStage = async (id, val, field, p) => {
    if (field === 'status') {
      setShowUpdateStatus({ ...p, newStatus: val });
      return;
    }
    // Handle other status updates if needed
  };

  const handleStatusSubmit = async (formData) => {
    try {
      await prospectApi.moveStage(showUpdateStatus._id || showUpdateStatus.id, formData, user?.token);
      setToastMsg('Status updated!');
      setShowUpdateStatus(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg(err.message || 'Failed to update status');
      setTimeout(() => setToastMsg(null), 5000);
    }
  };

  const handleDeleteProspect = async (id) => {
    if (!window.confirm('Are you sure you want to delete this prospect?')) return;
    try {
      await prospectApi.delete(id, user?.token);
      setToastMsg('Prospect deleted');
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg('Error deleting prospect');
      setTimeout(() => setToastMsg(null), 3000);
    }
  };

  const handleQuotationSubmit = async (data) => {
    try {
      // In real app, this might call an API to generate PDF or just log the interaction
      // For now, we simulate WhatsApp trigger as per legacy
      const text = `Hi ${data.prospect.name}, Please find the quotation for your requirement. Total: ₹${data.total}.`;
      window.open(`https://wa.me/${data.prospect.phone?.replace(/\D/g, '')}?text=${encodeURIComponent(text)}`, '_blank');

      await prospectApi.addInteraction(data.prospect._id || data.prospect.id, {
        type: 'WhatsApp',
        notes: `Sent Quotation: ₹${data.total}`,
        action: 'Quotation'
      }, user?.token);

      setToastMsg('Quotation sent & logged!');
      setShowQuotation(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg('Error sending quotation');
      setTimeout(() => setToastMsg(null), 3000);
    }
  };

  const handleBrochureSend = async (brochure, prospect) => {
    try {
      await brochureApi.send({ 
        brochureId: brochure._id, 
        clientPhone: prospect.phone,
        clientName: prospect.name 
      }, user?.token);

      setToastMsg(`Catalog "${brochure.title}" sent successfully!`);
      setShowBrochureSelector(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg('Failed to send catalog');
      setTimeout(() => setToastMsg(null), 3000);
    }
  };

  return { 
    showPhoneSearch, setShowPhoneSearch, 
    showProspectDetails, setShowProspectDetails, 
    showCreateProspect, setShowCreateProspect, 
    showQuotation, setShowQuotation, 
    showUpdateStatus, setShowUpdateStatus, 
    showScheduleAppointment, setShowScheduleAppointment, 
    showBrochureSelector, setShowBrochureSelector,
    toastMsg, setToastMsg,
    handlePhoneSearch, handleProspectSubmit, handleUpdateStage, handleStatusSubmit, handleQuotationSubmit, handleDeleteProspect, handleBrochureSend
  };
};

export const useOrderFlow = (user, onSaved) => {
  const [showOrderSearch, setShowOrderSearch] = useState(false);
  const [showOrderClientDetails, setShowOrderClientDetails] = useState(null);
  const [showCreateOrder, setShowCreateOrder] = useState(null);
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [paymentOrder, setPaymentOrder] = useState(null);
  const [toastMsg, setToastMsg] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleOrderSearch = async (searchParams) => {
    setShowOrderSearch(false);
    try {
      const res = await orderApi.searchClient(searchParams, user?.token);
      if (res && res.found && res.data) {
        setShowOrderClientDetails(res.data);
      } else {
        setShowCreateOrder(searchParams);
      }
    } catch (err) {
      setShowCreateOrder(searchParams);
    }
  };

  const handleOrderSubmit = async (formData) => {
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      await orderApi.create(formData, user?.token);
      setToastMsg('Order created successfully!');
      setShowCreateOrder(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      console.error('[ORDER_SUBMIT_ERROR]', err);
      setToastMsg(err.message || 'Failed to create order');
      setTimeout(() => setToastMsg(null), 4000);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handlePaymentSubmit = async (paymentData) => {
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      await paymentApi.create({
        orderId: paymentOrder._id || paymentOrder.id,
        ...paymentData
      }, user?.token);
      setToastMsg('Payment submitted for verification!');
      setPaymentOrder(null);
      setTimeout(() => setToastMsg(null), 3000);
      if (onSaved) onSaved();
    } catch (err) {
      setToastMsg(err.message || 'Payment submission failed');
      setTimeout(() => setToastMsg(null), 4000);
    } finally {
      setIsSubmitting(false);
    }
  };

  return { 
    showOrderSearch, setShowOrderSearch, 
    showOrderClientDetails, setShowOrderClientDetails, 
    showCreateOrder, setShowCreateOrder, 
    selectedOrder, setSelectedOrder, 
    paymentOrder, setPaymentOrder, 
    toastMsg, setToastMsg,
    isSubmitting,
    handleOrderSearch, handleOrderSubmit, handlePaymentSubmit
  };
};

import React, { useState, useEffect } from 'react';
import { ShieldCheck, CheckCircle2, XCircle, Clock, Eye, ShoppingCart, Calendar, User, RefreshCw, IndianRupee, Package } from 'lucide-react';
import { approvalApi, leaveApi, orderApi, paymentApi } from '../../../services/api';
import { useAuth } from '../../../context/AuthContext';

// ─── Tab definitions ──────────────────────────────────────────────────────────
const TABS = [
  { key: 'AdvanceApproval',   label: 'Advance Payment Approval' },
  { key: 'OrderVerification', label: 'Order Verification'       },
  { key: 'PaymentVerification', label: 'Payment Verification'   },
  { key: 'Leaves',            label: 'Leaves'                   },
];

// ─── Status badge helper ──────────────────────────────────────────────────────
const StatusBadge = ({ status }) => {
  const isApproved = status === 'Approved' || status === 'Verified' || status?.includes('APPROVED');
  const isRejected = status === 'Rejected' || status?.includes('REJECTED');
  return (
    <span className={`text-[10px] font-black uppercase tracking-widest ${
      isApproved ? 'text-emerald-600' : isRejected ? 'text-rose-600' : 'text-amber-600'
    }`}>
      {status?.replace(/_/g, ' ')}
    </span>
  );
};

// ─── Empty state (reuses existing design) ────────────────────────────────────
const EmptyState = ({ icon: Icon, message }) => (
  <div className="py-20 text-center bg-white rounded-[2rem] border border-dashed border-slate-200">
    <Icon className="h-10 w-10 mx-auto text-slate-200 mb-3" />
    <p className="text-slate-500 font-bold">{message}</p>
  </div>
);

// ─── Card wrapper (reuses existing design) ───────────────────────────────────
const Card = ({ children }) => (
  <div className="bg-white border border-slate-100 rounded-[2rem] p-6 shadow-sm flex flex-wrap lg:flex-nowrap gap-8 items-center group hover:shadow-md transition-all">
    {children}
  </div>
);

// ─── Stat column (reuses existing border-x design) ───────────────────────────
const StatCol = ({ label, value, valueClass = '' }) => (
  <div>
    <p className="text-[10px] font-black text-slate-400 uppercase mb-1">{label}</p>
    <p className={`font-black ${valueClass}`}>{value}</p>
  </div>
);

// ─── Main Component ───────────────────────────────────────────────────────────
const ApprovalsTerminal = () => {
  const { user } = useAuth();


  const isAccountant = user.role === 'ACCOUNTS';

  // ── State
  const [activeTab, setActiveTab]           = useState(isAccountant ? 'PaymentVerification' : 'AdvanceApproval');
  const [approvals, setApprovals]           = useState([]);   // OrderApproval records (tab 1)
  const [pendingOrders, setPendingOrders]   = useState([]);   // verificationStatus=Pending (tab 2)
  const [payments, setPayments]             = useState([]);   // Payment records (tab 3)
  const [leaves, setLeaves]                 = useState([]);   // Leave records (tab 4)
  const [loading, setLoading]               = useState(true);

  const [statusFilter, setStatusFilter]     = useState('Pending');
  const [selectedLeave, setSelectedLeave]   = useState(null);
  const [notes, setNotes]                   = useState('');

  const canReviewLeaves = ['HR', 'ADMIN', 'MD_CEO'].includes(user.role);

  // ── Data fetch ───────────────────────────────────────────────────────────────
  const fetchData = async () => {
    try {
      setLoading(true);

      // ── Leave status mapping (unchanged from original)
      let leaveStatus = '';
      if (statusFilter === 'Pending')  leaveStatus = 'PENDING,HR_APPROVED';
      else if (statusFilter === 'Approved') leaveStatus = 'HR_APPROVED,ADMIN_APPROVED';
      else if (statusFilter === 'Rejected') leaveStatus = 'HR_REJECTED,ADMIN_REJECTED';
      const leaveParams = leaveStatus ? { status: leaveStatus, employeeId: user._id } : { employeeId: user._id };

      // ── Approval (OrderApproval) params — tab 1
      const appParams = statusFilter ? { status: statusFilter, requestedBy: user._id } : { requestedBy: user._id };

      // ── Payment params — tab 3
      // Map statusFilter to payment status terminology
      let payStatus = statusFilter;
      if (statusFilter === 'Approved') payStatus = 'Verified';
      const payParams = payStatus ? { status: payStatus, collectedBy: user._id } : { collectedBy: user._id };

      // ── Fetch all in parallel
      const [appRes, leaveRes, payRes] = await Promise.all([
        approvalApi.list(appParams, user.token),
        leaveApi.list(leaveParams, user.token),
        paymentApi.list(payParams, user.token),
      ]);

      if (appRes.success)                         setApprovals(appRes.data);
      if (leaveRes.success || leaveRes.leaves)    setLeaves(leaveRes.leaves || leaveRes.data || []);
      if (payRes.success)                         setPayments(payRes.data);

      // ── Order Verification: fetch orders with verificationStatus filter
      const verifStatus = statusFilter === 'Approved' ? 'Verified' : statusFilter === 'Pending' ? 'Pending' : undefined;
      const orderParams = verifStatus ? { verificationStatus: verifStatus, salesExec: user._id } : { salesExec: user._id };
      const orderRes = await orderApi.list(orderParams, user.token);
      if (orderRes.success) {
        // For exec role: backend already limits to their own orders; managers see all
        setPendingOrders(orderRes.data.filter(o =>
          o.status !== 'Pending_Approval' &&
          o.status !== 'Draft' &&
          o.status !== 'Cancelled'
        ));
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [statusFilter]);

  // ── Loading state (unchanged from original)
  if (loading && !approvals.length && !leaves.length && !payments.length) {
    return <div className="flex h-96 items-center justify-center"><RefreshCw className="h-8 w-8 animate-spin text-blue-600" /></div>;
  }

  // ── Badge counts per tab ─────────────────────────────────────────────────────
  const badgeCounts = {
    AdvanceApproval:    approvals.filter(a => a.status === 'Pending').length,
    OrderVerification:  pendingOrders.filter(o => o.verificationStatus === 'Pending').length,
    PaymentVerification:payments.filter(p => p.status === 'Pending').length,
    Leaves:             leaves.filter(l => l.status === 'PENDING' || l.status === 'HR_APPROVED').length,
  };

  // ─────────────────────────────────────────────────────────────────────────────


  return (
    <div className="space-y-8 animate-in fade-in duration-700">

      {/* ── Header (unchanged) */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div className="flex flex-col gap-1">
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">My Approvals</h1>
          <p className="text-sm font-semibold text-slate-500">Track your order approvals, payment verifications, and leave requests.</p>
        </div>
      </div>

      {/* ── Tab bar + filter controls */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        {/* Tabs — same pill style as original */}
        <div className="flex flex-wrap p-1 bg-slate-100 rounded-2xl w-fit gap-0.5">
          {TABS.map((tab) => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`relative px-5 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${
                activeTab === tab.key ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
              }`}
            >
              {tab.label}
              {/* Pending count badge */}
              {badgeCounts[tab.key] > 0 && (
                <span className="ml-1.5 inline-flex items-center justify-center w-4 h-4 rounded-full bg-red-500 text-white text-[8px] font-black leading-none">
                  {badgeCounts[tab.key]}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Status dropdown + refresh — unchanged */}
        <div className="flex items-center gap-3">
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="h-10 rounded-xl border border-slate-200 bg-white px-4 text-[10px] font-black uppercase outline-none focus:border-blue-600"
          >
            <option value="">All History</option>
            <option value="Pending">Pending Approval</option>
            <option value="Approved">Approved / Verified</option>
            <option value="Rejected">Rejected</option>
          </select>
          <button
            onClick={fetchData}
            className="h-10 w-10 flex items-center justify-center rounded-xl bg-slate-50 text-slate-500 hover:bg-slate-100"
          >
            <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
          </button>
        </div>
      </div>

      {/* ── Tab content */}
      <div className="space-y-4">

        {/* ══ TAB 1: Advance Payment Approval ════════════════════════════════════ */}
        {activeTab === 'AdvanceApproval' && (
          approvals.length === 0 ? (
            <EmptyState icon={ShoppingCart} message="No advance payment approvals found" />
          ) : (
            approvals.map((app) => (
              <Card key={app._id}>
                {/* Identity */}
                <div className="flex-1 min-w-[200px]">
                  <div className="flex items-center gap-3 mb-2">
