            {tab}
          </button>
        ))}
      </div>

      {activeTab === 'Employees'    && <EmployeeList />}
      {activeTab === 'HR Activity'  && <HRActivity />}
      {activeTab === 'Audit Trail'  && <AuditTrail />}
      {activeTab === 'Metrics'      && <HRMetrics />}
    </div>
  );
};

export default AdminHR;

