import React, { useState, useEffect } from 'react';
import { Plus, MoreVertical, Image, FileText, Video, Layout } from 'lucide-react';
import useApi from '../hooks/useApi';

const COLUMNS = ['Pending', 'In Progress', 'Demo Shared', 'Approved'];

const typeIcon = { Social: Image, Email: FileText, Print: FileText, Video: Video, Web: Layout, Brand: Image };
const typeColor = {
  Social: 'bg-pink-100 text-pink-700', Email: 'bg-blue-100 text-blue-700',
  Print: 'bg-orange-100 text-orange-700', Video: 'bg-red-100 text-red-700',
  Web: 'bg-purple-100 text-purple-700', Brand: 'bg-cyan-100 text-cyan-700',
};
const priorityDot = { High: 'bg-red-500', Medium: 'bg-yellow-500', Low: 'bg-blue-400' };
const colHeaderColor = {
  Pending: 'border-gray-300', 'In Progress': 'border-blue-400',
  'Demo Shared': 'border-yellow-400', Approved: 'border-green-400',
};

const Design = () => {
  const { data, loading, error, refetch } = useApi('/orders?designStatus=Pending,In_Progress,Demo_Shared,Approved');
  const [cards, setCards] = useState({ Pending: [], 'In Progress': [], 'Demo Shared': [], Approved: [] });

  useEffect(() => {
    if (data?.data) {
      const grouped = { Pending: [], 'In Progress': [], 'Demo Shared': [], Approved: [] };
      data.data.forEach(order => {
        const status = order.designStatus === 'Demo_Shared' ? 'Demo Shared' : 
                       order.designStatus === 'In_Progress' ? 'In Progress' : order.designStatus;
        if (grouped[status]) {
          grouped[status].push({
            id: order._id,
            title: order.orderNumber + ' - ' + (order.clientSnapshot?.company || 'No Company'),
            client: order.clientSnapshot?.name || 'Unknown Client',
            type: 'Social', // Default type as backend doesn't have it explicitly per order yet
            assignee: order.designAssignedTo?.name || 'Unassigned',
            priority: 'Medium', // Placeholder
          });
        }
      });
      setCards(grouped);
    }
  }, [data]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Design Assets</h1>
          <p className="text-muted-foreground">Manage creative requests with a Kanban board.</p>
        </div>
        <button onClick={() => refetch()} className="inline-flex items-center justify-center rounded-md bg-primary px-4 py-2 text-sm font-medium text-primary-foreground hover:bg-primary/90 transition-colors">
          Refresh Board
        </button>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="h-8 w-8 rounded-full border-2 border-primary border-t-transparent animate-spin" />
        </div>
      ) : error ? (
        <div className="p-6 text-sm text-red-500 bg-red-50 rounded-xl border border-red-200">Error loading designs: {error}</div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4 items-start">
          {COLUMNS.map(col => (
            <div key={col} className="flex flex-col gap-3">
              {/* Column Header */}
              <div className={`flex items-center justify-between rounded-lg border-l-4 bg-card px-4 py-3 shadow-sm ${colHeaderColor[col]}`}>
                <span className="font-semibold text-sm">{col}</span>
                <span className="flex h-5 w-5 items-center justify-center rounded-full bg-muted text-xs font-bold text-muted-foreground">
                  {cards[col]?.length || 0}
                </span>
              </div>

              {/* Cards */}
              <div className="space-y-3">
                {cards[col]?.map(card => {
                  const TypeIcon = typeIcon[card.type] || FileText;
                  return (
                    <div key={card.id} className="rounded-xl border bg-card p-4 shadow-sm hover:shadow-md transition-all cursor-pointer group">
                      <div className="flex items-start justify-between mb-3">
                        <span className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs font-semibold ${typeColor[card.type] || 'bg-muted text-muted-foreground'}`}>
                          <TypeIcon className="h-3 w-3" />{card.type}
                        </span>
                        <button className="opacity-0 group-hover:opacity-100 transition-opacity text-muted-foreground hover:text-foreground">
                          <MoreVertical className="h-4 w-4" />
                        </button>
                      </div>
                      <h4 className="text-sm font-medium leading-snug mb-2">{card.title}</h4>
                      <p className="text-xs text-muted-foreground mb-3">{card.client}</p>
                      <div className="flex items-center justify-between">
                        <span className="text-xs text-muted-foreground">{card.assignee}</span>
                        <div className="flex items-center gap-1.5">
                          <div className={`h-2 w-2 rounded-full ${priorityDot[card.priority] || 'bg-gray-400'}`} />
                          <span className="text-xs text-muted-foreground">{card.priority}</span>
                        </div>
                      </div>
                    </div>
                  );
                })}
                {cards[col]?.length === 0 && (
                   <div className="text-center py-8 border border-dashed rounded-xl text-xs text-muted-foreground bg-muted/5">
                      No items in {col}
                   </div>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default Design;

import React, { useState } from 'react';
import { MapPin, CheckCircle2, Clock, Plus, Truck, AlertCircle, X, Search, Camera, User, Phone as PhoneIcon, Building, Calendar as CalendarIcon, FileText } from 'lucide-react';
import useApi from '../hooks/useApi';
import EmptyState from '../components/ui/EmptyState';

const statusStyle = {
  Completed: 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400',
  'In Progress': 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
  Pending: 'bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400',
};

const priorityStyle = {
  High: 'text-red-500', Medium: 'text-yellow-500', Low: 'text-blue-500',
};

const typeColors = {
  Installation: 'bg-purple-100 text-purple-700', Survey: 'bg-cyan-100 text-cyan-700',
  Maintenance: 'bg-orange-100 text-orange-700', Shoot: 'bg-pink-100 text-pink-700', Visit: 'bg-indigo-100 text-indigo-700',
};

const TYPES = ['All', 'Installation', 'Survey', 'Maintenance', 'Shoot', 'Visit'];

const Field = () => {
  const { data, loading, error, refetch } = useApi('/visits');
  const [filter, setFilter] = useState('All');

  // Modals state
  const [searchModalOpen, setSearchModalOpen] = useState(false);
  const [detailsModalOpen, setDetailsModalOpen] = useState(false);
  const [newVisitModalOpen, setNewVisitModalOpen] = useState(false);

  // Search state
  const [searchPhone, setSearchPhone] = useState('');
  const [searchCompany, setSearchCompany] = useState('');
  const [foundVisit, setFoundVisit] = useState(null);

  // New Visit Form state
  const [newVisitForm, setNewVisitForm] = useState({
    clientName: '',
    phone: '',
    businessName: '',
    date: new Date().toISOString().split('T')[0],
    location: '',
    purpose: 'Site Visit',
    notes: '',
  });

  const visits = data?.data || [];
  const filtered = visits.filter(v => filter === 'All' || v.visitType === filter);
  const completedCount = visits.filter(v => v.status === 'Completed').length;
  const inProgressCount = visits.filter(v => v.status === 'In Progress').length;

  const handleSearch = () => {
    if (!searchPhone && !searchCompany) return;

    // Check if visit exists for this phone or company (using generic match since 'visits' may have different structure)
    const match = visits.find(v => 
      (searchPhone && (v.phone?.includes(searchPhone) || v.clientPhone?.includes(searchPhone))) || 
      (searchCompany && (v.businessName?.toLowerCase().includes(searchCompany.toLowerCase()) || v.company?.toLowerCase().includes(searchCompany.toLowerCase())))
    );

    setSearchModalOpen(false);

    if (match) {
      setFoundVisit(match);
      setDetailsModalOpen(true);
    } else {
      setNewVisitForm(prev => ({ ...prev, phone: searchPhone, businessName: searchCompany, date: new Date().toISOString().split('T')[0] }));
      setNewVisitModalOpen(true);
    }
  };

  const handleGetLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((position) => {
        setNewVisitForm(prev => ({
          ...prev,
          location: `${position.coords.latitude.toFixed(4)}, ${position.coords.longitude.toFixed(4)}`
        }));
      }, () => {
        alert("Unable to retrieve your location.");
      });
    } else {
      alert("Geolocation not supported.");
    }
  };

  const handleScheduleVisit = (e) => {
    e.preventDefault();
    // Simulate API call to schedule visit
    alert("Visit Scheduled successfully!");
    setNewVisitModalOpen(false);
  };

  // Format date as dd-mm-yyyy for display
  const formatDateDisplay = (dateString) => {
    if (!dateString) return '';
    const [year, month, day] = dateString.split('-');
    return `${day}-${month}-${year}`;
  };

  return (
    <div className="space-y-6 relative">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Field Operations</h1>
          <p className="text-muted-foreground">Track on-ground campaign activities and site visits.</p>
        </div>
        <button onClick={() => { setSearchPhone(''); setSearchCompany(''); setSearchModalOpen(true); }} className="inline-flex items-center justify-center rounded-md bg-[#003366] px-5 py-2.5 text-sm font-semibold text-white hover:bg-[#003366]/90 transition-all shadow-md hover:shadow-lg hover:-translate-y-0.5">
          <Plus className="mr-2 h-4 w-4" /> Add Visit
        </button>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <div className="h-8 w-8 rounded-full border-2 border-primary border-t-transparent animate-spin" />
        </div>
      ) : error ? (
        <div className="p-6 text-sm text-red-500 bg-red-50 rounded-xl border border-red-200">Error: {error}</div>
      ) : (
        <>
          {/* Summary */}
          <div className="grid gap-4 grid-cols-3">
            {[
              { label: 'Total Tasks', value: visits.length, icon: Truck, color: 'bg-primary/10 text-primary' },
              { label: 'In Progress', value: inProgressCount, icon: Clock, color: 'bg-blue-100 text-blue-600' },
              { label: 'Completed', value: completedCount, icon: CheckCircle2, color: 'bg-green-100 text-green-600' },
            ].map(({ label, value, icon: Icon, color }) => (
              <div key={label} className="rounded-xl border bg-card p-5 shadow-sm flex items-center gap-4">
                <div className={`h-10 w-10 rounded-full flex items-center justify-center shrink-0 ${color}`}><Icon className="h-5 w-5" /></div>
                <div><p className="text-2xl font-bold">{value}</p><p className="text-sm text-muted-foreground">{label}</p></div>
              </div>
            ))}
          </div>

          {/* Type Filters */}
          <div className="flex gap-2 flex-wrap">
            {TYPES.map(t => (
              <button key={t} onClick={() => setFilter(t)}
                className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors border ${filter === t ? 'bg-[#003366] text-white border-[#003366] shadow-sm' : 'bg-background hover:bg-muted border-input text-muted-foreground'}`}>
                {t}
              </button>
            ))}
          </div>

          {/* Task Cards */}
          <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            {filtered.map(visit => (
              <div key={visit._id || Math.random()} className="rounded-xl border bg-card p-5 shadow-sm hover:shadow-lg transition-all duration-300 flex flex-col gap-4 group">
                <div className="flex items-start justify-between gap-2">
