                  <p>You'll be asked to set a new password on first login.</p>
                </div>
              </form>
            </>
          )}
        </div>

        <p className="text-center text-xs text-blue-400 mt-4">
          Don't have credentials? Contact your HR department.
        </p>
      </div>
    </div>
  );
};

