          </span>
        )}
      </div>

      <div className="mt-6">
        <div className="flex items-baseline gap-2">
          <h3 className="text-3xl font-black text-slate-900">{value}</h3>
          {total !== undefined && <span className="text-lg font-bold text-slate-400">/ {total}</span>}
